    25→fn create_sample_ndjson_file(dir: &TempDir) -> Utf8PathBuf {
    26→    let path = dir.path().join("events.json");
    27→    // Create a proper FixtureFile format for JsonFixtureAdapter (used by ingest command)
    28→    let fixture = r#"{
    29→  "version": 1,
    30→  "description": "Test fixture",
    31→  "events": [
    32→    {
    33→      "timestamp_ns": 1710000000000000000,
    34→      "transport": "grpc",
    35→      "direction": "outbound",
    36→      "payload_base64": "dGVzdA==",
    37→      "metadata": {}
    38→    }
    39→  ]
    40→}"#;
    41→    fs::write(&path, fixture).unwrap();
    42→    Utf8PathBuf::from_path_buf(path).unwrap()
    43→}
    44→
    45→fn create_debug_events_ndjson(dir: &TempDir) -> Utf8PathBuf {
    46→    let path = dir.path().join("events.ndjson");
    47→    // Create actual NDJSON (DebugEvent per line) for inspect/export/merge commands
    48→    let event = r#"{"id":1,"timestamp":1710000000000000000,"source":{"adapter":"test","origin":"test"},"transport":"grpc","direction":"outbound","payload":{"type":"raw","raw":"dGVzdA=="},"metadata":{}}"#;
    49→    fs::write(&path, event).unwrap();
    50→    Utf8PathBuf::from_path_buf(path).unwrap()
    51→}
    52→
    53→fn create_sample_proto_file(dir: &TempDir) -> Utf8PathBuf {
    54→    let path = dir.path().join("test.proto");
    55→    let proto_content = r#"
    56→syntax = "proto3";
    57→package test;
    58→
    59→message TestMessage {
    60→    int32 id = 1;
    61→    string name = 2;
    62→}
    63→
    64→service TestService {
    65→    rpc GetTest(TestMessage) returns (TestMessage);
    66→}
    67→"#;
    68→    fs::write(&path, proto_content).unwrap();
    69→    Utf8PathBuf::from_path_buf(path).unwrap()
    70→}
