    72→fn create_sample_otlp_json(dir: &TempDir) -> Utf8PathBuf {
    73→    let path = dir.path().join("traces.json");
    74→    let content = r#"{
    75→        "resourceSpans": [{
    76→            "resource": {
    77→                "attributes": [
    78→                    {"key": "service.name", "value": {"stringValue": "test-service"}}
    79→                ]
    80→            },
    81→            "scopeSpans": [{
    82→                "scope": {"name": "test", "version": "1.0"},
    83→                "spans": [{
    84→                    "traceId": "4bf92f3577b34da6a3ce929d0e0e4736",
    85→                    "spanId": "00f067aa0ba902b7",
    86→                    "name": "/api.v1.Users/Get",
    87→                    "kind": 3,
    88→                    "startTimeUnixNano": "1710000000000000000",
    89→                    "endTimeUnixNano": "1710000000100000000",
    90→                    "attributes": []
    91→                }]
    92→            }]
    93→        }]
    94→    }"#;
    95→    fs::write(&path, content).unwrap();
    96→    Utf8PathBuf::from_path_buf(path).unwrap()
    97→}
