    99→fn create_plugin_dir_with_manifest(dir: &TempDir, plugin_name: &str) -> PathBuf {
   100→    let plugin_dir = dir.path().join(plugin_name);
   101→    fs::create_dir_all(&plugin_dir).unwrap();
   102→
   103→    let manifest = r#"
   104→[plugin]
   105→name = "test-plugin"
   106→version = "1.0.0"
   107→description = "Test plugin"
   108→api_version = "1.0"
   109→protocol_id = "test-proto"
   110→type = "native"
   111→library = "libtest.so"
   112→"#;
   113→    let manifest_path = plugin_dir.join("plugin.toml");
   114→    fs::write(&manifest_path, manifest).unwrap();
   115→
   116→    plugin_dir
   117→}
