                                event.timestamp.as_nanos() as f64 / 1_000_000_000.0,
                                event.transport,
                                src,
                                dst
                            )?;
                        }
                        CaptureOutputFormat::Json => {
                            // Full NDJSON event
                            serde_json::to_writer(&mut stdout, &event)?;
                            writeln!(stdout)?;
                        }
                    }
                    stdout.flush()?;
                }
                count += 1;
            }
            Err(e) => {
                tracing::warn!("Event processing error: {}", e);
            }
        }
    }

